using System.ComponentModel;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that call an external API using HttpClient.
/// Uses constructor injection so HttpClient is resolved via DI (IHttpClientFactory).
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetches data from an external API endpoint and returns the response body.")]
    public async Task<string> FetchApiData(
        [Description("Relative or absolute URL path to fetch (e.g. /posts/1)")] string path,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching API data from {Path}", path);

        var response = await httpClient.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        logger.LogInformation("Received {Length} characters from {Path}", content.Length, path);

        return content;
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

/// <summary>
/// Reusable prompt templates for summarization tasks.
/// </summary>
[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Summarize the provided content into a concise paragraph.")]
    public static ChatMessage Summarize(
        [Description("The text content to summarize")] string content) =>
        new(ChatRole.User, $"Summarize the following content into a concise paragraph:\n\n{content}");

    [McpServerPrompt, Description("Summarize content with a specified maximum number of sentences.")]
    public static ChatMessage SummarizeWithLimit(
        [Description("The text content to summarize")] string content,
        [Description("Maximum number of sentences in the summary")] int maxSentences = 3) =>
        new(ChatRole.User,
            $"Summarize the following content in at most {maxSentences} sentences:\n\n{content}");
}

